  DELETE FROM document.charte WHERE tenant_id = 'test';

  v_id := document.charte_create(
    p_name := 'Load Test',
    p_color_bg := '#FAF6F1',
    p_color_main := '#2C3E2D',
    p_color_accent := '#C4956A',
    p_color_text := '#3D3D3D',
    p_color_text_light := '#8A8A8A',
    p_color_border := '#E8E0D8',
    p_color_extra := '{"olive":"#5C6B3C"}'::jsonb,
    p_font_heading := 'Cormorant Garamond',
    p_font_body := 'Source Sans 3',
    p_spacing_page := '15mm',
    p_shadow_card := '0 1mm 4mm rgba(0,0,0,0.08)'
  );

  v_result := document.charte_load('Load Test');

  RETURN NEXT ok(v_result IS NOT NULL, 'charte_load returns data');
  RETURN NEXT is(v_result->>'name', 'Load Test', 'name in result');
  RETURN NEXT ok(v_result->>'context_token' IS NOT NULL, 'context_token present');
  RETURN NEXT is(length(v_result->>'context_token'), 32, 'context_token is md5 (32 chars)');

  -- CSS check
  v_css := v_result->>'css';
  RETURN NEXT ok(v_css LIKE '%--charte-color-bg: #FAF6F1%', 'CSS contains color_bg variable');
  RETURN NEXT ok(v_css LIKE '%--charte-color-olive: #5C6B3C%', 'CSS contains color_extra olive');
  RETURN NEXT ok(v_css LIKE '%--charte-font-heading%', 'CSS contains font_heading');
  RETURN NEXT ok(v_css LIKE '%--charte-spacing-page: 15mm%', 'CSS contains spacing');
  RETURN NEXT ok(v_css LIKE '%--charte-shadow-card%', 'CSS contains shadow');
  RETURN NEXT ok(v_css LIKE '%@import url%Cormorant+Garamond%', 'Google Font import for heading');
  RETURN NEXT ok(v_css LIKE '%@import url%Source+Sans+3%', 'Google Font import for body');

  -- Colors
  RETURN NEXT is(v_result->'colors'->>'bg', '#FAF6F1', 'colors.bg');
  RETURN NEXT is(v_result->'colors'->'extra'->>'olive', '#5C6B3C', 'colors.extra.olive');

  -- Not found
  RETURN NEXT ok(document.charte_load('Nonexistent') IS NULL, 'returns NULL for unknown charte');

  DELETE FROM document.charte WHERE tenant_id = 'test';
END;
$function$;
COMMENT ON FUNCTION document_ut.test_charte_load() IS 'Test charte load — CSS output, context_token, voice';

CREATE OR REPLACE FUNCTION document_ut.test_doc_create()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_id text;
  v_charte_id text;
  v_d record;
  v_page_cnt int;
BEGIN
  PERFORM set_config('app.tenant_id', 'test', true);
  DELETE FROM document.document WHERE tenant_id = 'test';
  DELETE FROM document.charte WHERE tenant_id = 'test';

  -- A4 portrait
  v_id := document.doc_create('Test A4');
  SELECT * INTO v_d FROM document.document WHERE id = v_id;
  RETURN NEXT is(v_d.width, 210::numeric, 'A4 width = 210');
  RETURN NEXT is(v_d.height, 297::numeric, 'A4 height = 297');
  RETURN NEXT is(v_d.format, 'A4', 'format stored');
  RETURN NEXT is(v_d.orientation, 'portrait', 'orientation default portrait');

  -- First page created
  SELECT count(*)::int INTO v_page_cnt FROM document.page WHERE doc_id = v_id;
  RETURN NEXT is(v_page_cnt, 1, 'first page auto-created');

  -- A3 landscape (swap)
  v_id := document.doc_create('Test A3 L', p_format := 'A3', p_orientation := 'landscape');
  SELECT * INTO v_d FROM document.document WHERE id = v_id;
  RETURN NEXT is(v_d.width, 420::numeric, 'A3 landscape width = 420');
  RETURN NEXT is(v_d.height, 297::numeric, 'A3 landscape height = 297');

  -- HD (no swap for screen)
  v_id := document.doc_create('Test HD', p_format := 'HD');
  SELECT * INTO v_d FROM document.document WHERE id = v_id;
  RETURN NEXT is(v_d.width, 1920::numeric, 'HD width = 1920');
  RETURN NEXT is(v_d.height, 1080::numeric, 'HD height = 1080');

  -- With charte
  v_charte_id := document.charte_create(p_name := 'Test DC', p_color_bg := '#fff', p_color_main := '#000',
    p_color_accent := '#f00', p_color_text := '#333', p_color_text_light := '#888', p_color_border := '#eee',
    p_font_heading := 'Inter', p_font_body := 'Inter');
  v_id := document.doc_create('With Charte', p_charte_id := v_charte_id);
  SELECT * INTO v_d FROM document.document WHERE id = v_id;
  RETURN NEXT is(v_d.charte_id, v_charte_id, 'charte linked');

  -- With initial HTML
  v_id := document.doc_create('With HTML', p_html := '<div data-id="h1">Hello</div>');
  RETURN NEXT is(
    (SELECT html FROM document.page WHERE doc_id = v_id AND page_index = 0),
    '<div data-id="h1">Hello</div>', 'initial HTML stored');

  DELETE FROM document.document WHERE tenant_id = 'test';
  DELETE FROM document.charte WHERE tenant_id = 'test';
END;
$function$;
COMMENT ON FUNCTION document_ut.test_doc_create() IS 'Test doc creation — format→dimensions, landscape swap, charte link';

CREATE OR REPLACE FUNCTION document_ut.test_doc_duplicate()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_src text;
  v_dup text;
  v_src_pages int;
  v_dup_pages int;
  v_dup_html text;
BEGIN
  PERFORM set_config('app.tenant_id', 'test', true);
  DELETE FROM document.document WHERE tenant_id = 'test';

  v_src := document.doc_create('Original', p_html := '<div data-id="h">Hello</div>');
  PERFORM document.page_add(v_src, 'P2', '<p>Page 2</p>');

  v_dup := document.doc_duplicate(v_src, 'Copy');

  RETURN NEXT ok(v_dup IS NOT NULL, 'duplicate returns new id');
  RETURN NEXT ok(v_dup != v_src, 'different id');
  RETURN NEXT is(
    (SELECT name FROM document.document WHERE id = v_dup), 'Copy', 'new name');
  RETURN NEXT is(
    (SELECT format FROM document.document WHERE id = v_dup), 'A4', 'format copied');

  SELECT count(*)::int INTO v_src_pages FROM document.page WHERE doc_id = v_src;
  SELECT count(*)::int INTO v_dup_pages FROM document.page WHERE doc_id = v_dup;
  RETURN NEXT is(v_dup_pages, v_src_pages, 'same page count');

  SELECT html INTO v_dup_html FROM document.page WHERE doc_id = v_dup AND page_index = 0;
  RETURN NEXT is(v_dup_html, '<div data-id="h">Hello</div>', 'HTML cloned');

  DELETE FROM document.document WHERE tenant_id = 'test';
END;
$function$;
COMMENT ON FUNCTION document_ut.test_doc_duplicate() IS 'Test doc duplicate — deep clone with pages';

