  v_id := document.doc_create('Print HD', p_format := 'HD');
  v_css := document.doc_print_css(v_id);
  RETURN NEXT ok(v_css LIKE '%size: 1920mm 1080mm%', 'HD @page size (no swap)');

  -- Not found
  RETURN NEXT ok(document.doc_print_css('nonexistent') IS NULL, 'NULL for unknown doc');

  DELETE FROM document.document WHERE tenant_id = 'test';
END;
$function$;
