    RETURN NEXT fail('duplicate name should raise');
  EXCEPTION WHEN unique_violation THEN
    RETURN NEXT pass('duplicate name raises unique_violation');
  END;

  DELETE FROM document.library WHERE tenant_id = 'test';
END;
$function$;
COMMENT ON FUNCTION document_ut.test_library_create() IS 'Test library creation — unique name per tenant';

CREATE OR REPLACE FUNCTION document_ut.test_library_delete()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_lib_id text;
  v_asset_id uuid;
  v_doc_id text;
  v_cnt int;
BEGIN
  PERFORM set_config('app.tenant_id', 'test', true);
  DELETE FROM document.document WHERE tenant_id = 'test';
  DELETE FROM document.library WHERE tenant_id = 'test';

  v_lib_id := document.library_create('To Delete');

  -- Add asset if available
  SELECT id INTO v_asset_id FROM asset.asset LIMIT 1;
  IF v_asset_id IS NOT NULL THEN
    PERFORM document.library_add_asset(v_lib_id, v_asset_id, 'test');
  END IF;

  -- Link a document
  v_doc_id := document.doc_create('Linked Doc', p_library_id := v_lib_id);

  RETURN NEXT ok(document.library_delete('To Delete'), 'delete returns true');

  SELECT count(*)::int INTO v_cnt FROM document.library WHERE id = v_lib_id;
  RETURN NEXT is(v_cnt, 0, 'library removed');

  -- Document still exists, library_id NULL
  RETURN NEXT ok(
    (SELECT library_id IS NULL FROM document.document WHERE id = v_doc_id),
    'document library_id set to NULL'
  );

  RETURN NEXT ok(NOT document.library_delete('Nonexistent'), 'delete unknown returns false');

  DELETE FROM document.document WHERE tenant_id = 'test';
END;
$function$;
COMMENT ON FUNCTION document_ut.test_library_delete() IS 'Test library delete — cascade library_asset, FK SET NULL on documents';

CREATE OR REPLACE FUNCTION document_ut.test_library_load()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_lib_id text;
  v_asset_id uuid;
  v_result jsonb;
BEGIN
  PERFORM set_config('app.tenant_id', 'test', true);
  DELETE FROM document.library WHERE tenant_id = 'test';

  v_lib_id := document.library_create('Load Test', 'Test library');

  SELECT id INTO v_asset_id FROM asset.asset LIMIT 1;
  IF v_asset_id IS NULL THEN
    RETURN NEXT skip('no assets in database');
    DELETE FROM document.library WHERE tenant_id = 'test';
    RETURN;
  END IF;

  PERFORM document.library_add_asset(v_lib_id, v_asset_id, 'logo', 'Logo entreprise');

  v_result := document.library_load(v_lib_id);

  RETURN NEXT ok(v_result IS NOT NULL, 'library_load returns data');
  RETURN NEXT is(v_result->>'name', 'Load Test', 'name in result');
  RETURN NEXT is(jsonb_array_length(v_result->'assets'), 1, '1 asset');
  RETURN NEXT ok(v_result->'assets'->0->>'filename' IS NOT NULL, 'asset filename present');
  RETURN NEXT is(v_result->'assets'->0->>'role', 'logo', 'asset role present');

  -- Not found
  RETURN NEXT ok(document.library_load('nonexistent') IS NULL, 'NULL for unknown library');

  DELETE FROM document.library WHERE tenant_id = 'test';
END;
$function$;
COMMENT ON FUNCTION document_ut.test_library_load() IS 'Test library_load — returns library + asset metadata';

CREATE OR REPLACE FUNCTION document_ut.test_normalize_color()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
BEGIN
  RETURN NEXT is(document.normalize_color('#ff0080'), '#ff0080', 'hex 6 lowercase unchanged');
  RETURN NEXT is(document.normalize_color('#FF0080'), '#ff0080', 'hex 6 uppercase');
  RETURN NEXT is(document.normalize_color('#FFF'), '#ffffff', 'hex 3 → 6');
  RETURN NEXT is(document.normalize_color('#abc'), '#aabbcc', 'hex 3 lowercase');
  RETURN NEXT is(document.normalize_color('rgb(255, 0, 128)'), '#ff0080', 'rgb()');
  RETURN NEXT is(document.normalize_color('rgb(0, 0, 0)'), '#000000', 'rgb black');
  RETURN NEXT ok(document.normalize_color('not-a-color') IS NULL, 'invalid returns NULL');
  RETURN NEXT ok(document.normalize_color('red') IS NULL, 'named color returns NULL');
END;
$function$;
COMMENT ON FUNCTION document_ut.test_normalize_color() IS 'Test normalize_color — hex 3/6 digits, rgb(), invalid';

CREATE OR REPLACE FUNCTION document_ut.test_page_add_remove()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_id text;
  v_idx int;
  v_cnt int;
  v_names text[];
BEGIN
  PERFORM set_config('app.tenant_id', 'test', true);
  DELETE FROM document.document WHERE tenant_id = 'test';

  v_id := document.doc_create('Pages Test');

  -- Add pages
  v_idx := document.page_add(v_id, 'Page 2');
  RETURN NEXT is(v_idx, 1, 'page_add returns index 1');

  v_idx := document.page_add(v_id, 'Page 3');
  RETURN NEXT is(v_idx, 2, 'page_add returns index 2');

  SELECT count(*)::int INTO v_cnt FROM document.page WHERE doc_id = v_id;
  RETURN NEXT is(v_cnt, 3, '3 pages total');

  -- Remove middle page (index 1)
  RETURN NEXT ok(document.page_remove(v_id, 1), 'remove page 1');

  SELECT count(*)::int INTO v_cnt FROM document.page WHERE doc_id = v_id;
  RETURN NEXT is(v_cnt, 2, '2 pages after remove');

  -- Check renumbering: remaining pages should be 0, 1
  SELECT array_agg(name ORDER BY page_index) INTO v_names FROM document.page WHERE doc_id = v_id;
  RETURN NEXT is(v_names, ARRAY['Page 1', 'Page 3'], 'pages renumbered correctly');

  -- Remove until 1 page left
  PERFORM document.page_remove(v_id, 1);
  -- Try to remove the last page
  BEGIN
    PERFORM document.page_remove(v_id, 0);
    RETURN NEXT fail('should raise on last page');
  EXCEPTION WHEN OTHERS THEN
    RETURN NEXT pass('raises on last page removal');
  END;

  DELETE FROM document.document WHERE tenant_id = 'test';
END;
$function$;
COMMENT ON FUNCTION document_ut.test_page_add_remove() IS 'Test page add/remove — append, remove with renumber, refuse last page';

CREATE OR REPLACE FUNCTION document_ut.test_page_set_html()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_id text;
  v_cnt int;
  v_rev_cnt int;
  v_html text;
BEGIN
  PERFORM set_config('app.tenant_id', 'test', true);
  DELETE FROM document.document WHERE tenant_id = 'test';

  v_id := document.doc_create('HTML Test', p_html := '<div data-id="v1">Version 1</div>');

  -- Set new HTML
  v_cnt := document.page_set_html(v_id, 0, '<div data-id="v2">Version 2</div><span data-id="s1">Span</span>');
  RETURN NEXT is(v_cnt, 2, 'returns 2 data-id elements');

  -- Check HTML updated
  SELECT html INTO v_html FROM document.page WHERE doc_id = v_id AND page_index = 0;
  RETURN NEXT ok(v_html LIKE '%Version 2%', 'HTML updated');

  -- Check revision created
  SELECT count(*)::int INTO v_rev_cnt FROM document.page_revision WHERE doc_id = v_id AND page_index = 0;
  RETURN NEXT is(v_rev_cnt, 1, '1 revision saved');

  -- Check revision content
  RETURN NEXT is(
    (SELECT html FROM document.page_revision WHERE doc_id = v_id AND page_index = 0 AND version = 1),
    '<div data-id="v1">Version 1</div>', 'revision has old HTML');

  -- Second update
  v_cnt := document.page_set_html(v_id, 0, '<p data-id="v3">V3</p>');
  SELECT count(*)::int INTO v_rev_cnt FROM document.page_revision WHERE doc_id = v_id AND page_index = 0;
  RETURN NEXT is(v_rev_cnt, 2, '2 revisions after second update');

  DELETE FROM document.document WHERE tenant_id = 'test';
END;
$function$;
COMMENT ON FUNCTION document_ut.test_page_set_html() IS 'Test page_set_html — HTML saved, revision created, data-id count';

CREATE OR REPLACE FUNCTION document_ut.test_style_merge()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
BEGIN
  -- jsonb keys are sorted alphabetically
  RETURN NEXT is(document.style_merge('width:210mm;color:red', 'color:blue;font-size:4mm'),
    'color:blue;width:210mm;font-size:4mm', 'merge with overwrite');
  RETURN NEXT is(document.style_merge('', 'color:red'), 'color:red', 'empty existing');
  RETURN NEXT is(document.style_merge('width:10mm', ''), 'width:10mm', 'empty new');
  RETURN NEXT is(document.style_merge(NULL, 'a:b'), 'a:b', 'NULL existing');
  RETURN NEXT is(document.style_merge('a:1;b:2', 'b:3;c:4'), 'a:1;b:3;c:4', 'partial overwrite');
END;
$function$;
COMMENT ON FUNCTION document_ut.test_style_merge() IS 'Test style_merge — basic merge, overwrite, new properties';

CREATE OR REPLACE FUNCTION document_ut.test_xhtml_patch()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_html text;
  v_result text;
BEGIN
  -- STYLE: add style to element without style
  v_html := '<div data-id="a">Hello</div>';
  v_result := document.xhtml_patch(v_html, '[{"id":"a","style":{"color":"red"}}]'::jsonb);
  RETURN NEXT ok(v_result LIKE '%style="color:red"%', 'style added to unstyled element');

  -- STYLE: merge with existing
  v_html := '<div data-id="a" style="width:10mm">Hello</div>';
  v_result := document.xhtml_patch(v_html, '[{"id":"a","style":{"color":"blue"}}]'::jsonb);
  RETURN NEXT ok(v_result LIKE '%color:blue%', 'style merged: new prop');
  RETURN NEXT ok(v_result LIKE '%width:10mm%', 'style merged: existing prop preserved');

  -- CONTENT: replace innerHTML
  v_html := '<div data-id="a">Old content</div>';
  v_result := document.xhtml_patch(v_html, '[{"id":"a","content":"New content"}]'::jsonb);
  RETURN NEXT ok(v_result LIKE '%New content%', 'content replaced');
  RETURN NEXT ok(v_result NOT LIKE '%Old content%', 'old content gone');

  -- REMOVE: delete element
  v_html := '<div data-id="keep">Keep</div><div data-id="rm">Remove me</div>';
  v_result := document.xhtml_patch(v_html, '[{"id":"rm","remove":true}]'::jsonb);
  RETURN NEXT ok(v_result LIKE '%Keep%', 'kept element preserved');
  RETURN NEXT ok(v_result NOT LIKE '%Remove me%', 'removed element gone');

  -- INSERT: add before closing tag
  v_html := '<div data-id="container"><p>Existing</p></div>';
  v_result := document.xhtml_patch(v_html, '[{"id":"container","insert":"<p>Added</p>"}]'::jsonb);
  RETURN NEXT ok(v_result LIKE '%<p>Existing</p><p>Added</p>%', 'inserted before end');

  -- REPLACE: replace entire element
  v_html := '<div data-id="old">Old</div>';
  v_result := document.xhtml_patch(v_html, '[{"id":"old","replace":"<span data-id=\"new\">New</span>"}]'::jsonb);
  RETURN NEXT ok(v_result LIKE '%<span data-id="new">New</span>%', 'element replaced');
  RETURN NEXT ok(v_result NOT LIKE '%data-id="old"%', 'old element gone');

  -- INVALID: patch that breaks XML
  BEGIN
    v_html := '<div data-id="a">Hello</div>';
    PERFORM document.xhtml_patch(v_html, '[{"id":"a","content":"<b>unclosed"}]'::jsonb);
    RETURN NEXT fail('should raise on invalid XML');
  EXCEPTION WHEN OTHERS THEN
    RETURN NEXT pass('raises on invalid XML result');
  END;

  -- Unknown data-id: no-op
  v_html := '<div data-id="a">Hello</div>';
  v_result := document.xhtml_patch(v_html, '[{"id":"unknown","content":"X"}]'::jsonb);
  RETURN NEXT is(v_result, v_html, 'unknown data-id is no-op');
END;
$function$;
COMMENT ON FUNCTION document_ut.test_xhtml_patch() IS 'Test xhtml_patch — style, content, remove, insert, replace, invalid';

